`endif

always #100 clk_i_buf = ~clk_i_buf;
		// Initialize values to zero 
initial	begin
	{clk_i_buf, data_i_n, dly_adj_buf, dly_incdec_buf, dly_ld_buf } <= 'd0;
	data_i_p <= 'd1;
	@(negedge clk_i_buf);
	@(negedge clk_i_buf);

// Generating random stimulus 
	for (int i = 0; i < 1000; i = i + 1) begin
		data_i_n <= $urandom();
		data_i_p <= $urandom();
		dly_adj_buf <= $urandom();
		dly_incdec_buf <= $urandom();
		dly_ld_buf <= $urandom();
		@(negedge clk_i_buf);
